if(window.location.pathname!=='/blog'){window.history.replaceState({},'','/blog')}
const backBtn=document.querySelector('.back-btn');
if(backBtn){backBtn.addEventListener('click',function(e){e.preventDefault();sessionStorage.setItem('scrollToBlog','true');window.location.href='/home.html'})}
document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener('click',function(e){const href=this.getAttribute('href');if(href==='#'||href==='')return;e.preventDefault();const target=document.getElementById(href.substring(1));if(target){target.scrollIntoView({behavior:'smooth',block:'start'});history.replaceState(null,'',window.location.pathname)}})});
if(window.location.hash){const targetId=window.location.hash.substring(1);history.replaceState(null,'',window.location.pathname);window.addEventListener('load',()=>{const target=document.getElementById(targetId);if(target){target.scrollIntoView({behavior:'smooth',block:'start'})}})}